effect.shader:
const vec3 luminanceWeighting = vec3(0.2126, 0.7152, 0.0722);

void main() {
    float rad = angle * 0.0174533;
    float adjStrength = strength / 8.0;
    vec2 offset = vec2(cos(rad)*adjStrength,-sin(rad)*adjStrength);
    vec2 sampleLow = (vec4(acLayerNorm - offset,0.0,1.0) * acLayerToScreen).xy;
    vec2 sampleHigh = (vec4(acLayerNorm + offset,0.0,1.0) * acLayerToScreen).xy;
    vec4 colorLow = texture2DCv(inputImg.texture,sampleLow);
    vec4 colorHigh = texture2DCv(inputImg.texture,sampleHigh);
    vec4 colorMid = texture2DCv(inputImg.texture,acScreenNorm);
    vec4 outColor;
    if( centerChannel==0 ) {
        outColor = vec4(colorMid.r,colorLow.g,colorHigh.b,1.0);
    } else if( centerChannel==1 ) {
        outColor = vec4(colorLow.r,colorMid.g,colorHigh.b,1.0);
    } else {
        outColor = vec4(colorLow.r,colorHigh.g,colorMid.b,1.0);
    }
    if( mode==0 ) {
        gl_FragColor = outColor * colorMid.a;
    } else if( mode==1 ) {
        vec4 r = vec4(outColor.r, 0.0, 0.0, outColor.r);
        vec4 g = vec4(0.0, outColor.g, 0.0, outColor.g);
        vec4 b = vec4(0.0, 0.0, outColor.b, outColor.b);
        vec4 m = (r + g + b) / 3.;
        vec4 c = vec4(0.0,0.0,0.0,0.0);
        vec4 l = vec4(dot(luminanceWeighting * colorMid.rgb, vec3(1.0)));
        //c = colorMid + (c*(1.0-colorMid.a));
        c = m + (c*(1.0-m.a));
        c = l + (c*(1.0-l.a));
        //c = (colorMid + m)/2.;
        //c = r + (c*(1.0-r.a));
        //c = g + (c*(1.0-g.a));
        //c = b + (c*(1.0-b.a));
        gl_FragColor = c;
    } else if( mode==2 ) {
        gl_FragColor = vec4(outColor.rgb,colorMid.a);
    } else {
        gl_FragColor = outColor*((colorLow.a + colorMid.a + colorHigh.a)/3.);
    }

}
